'use strict'

// Stand-in for metro-runtime's asyncRequire helper: the module Metro's transform
// injects a require() of at every dynamic import() callsite. No package `exports`
// (like metro-runtime <= 0.80.x), so the extensionless subpath resolves through the
// field resolver's source-extension probing.
function asyncRequire(moduleID, paths, moduleName) {
  return require.importAll(moduleID)
}

module.exports = asyncRequire
